#include<bits/stdc++.h>
using namespace std;
int temp[3][3],a[101][101],b[101];
bool flag[101];
int main()
{
	int t,cnt;
	scanf("%d",&t);
	while(t--)
	{
		int n,m;
		scanf("%d%d",&n,&m);
		cnt=m;
		for(int i=1;i<=m;i++)
		{
			char ch;
			int cnt=0;
			getchar();
			while((ch=getchar())!=' ')
			{
				a[i][++cnt]=ch-'0';
			}
			scanf("%d",&b[i]);
		}
		memset(flag,0,sizeof(flag));
		while(cnt>0)
		{
			bool flag1=false;
			for(int i=1;i<=n;i++)
			{
				memset(temp,0,sizeof(temp));
				for(int j=1;j<=m;j++)
				{
					if(flag[j])
					{
						continue;
					}
					temp[a[j][i]][b[j]]=1;
				}
				if(temp[0][0]!=temp[0][1])
				{
					for(int j=1;j<=m;j++)
					{
						if(a[j][i]==0&&!flag[j])
						{
							cnt--;
							flag[j]=true;
							flag1=true;
						}
					}
				}
				if(temp[1][0]!=temp[1][1])
				{
					for(int j=1;j<=m;j++)
					{
						if(a[j][i]==1&&!flag[j])
						{
							cnt--;
							flag[j]=true;
							flag1=true;
						}
					}
				}
			}
			if(!flag1&&cnt>0)
			{
				printf("LIE\n");
				break;
			}
		}
		if(cnt==0)
		{
			printf("OK\n");
		}
	}
	return 0;
}
